        if expiry_date:
            today = date.today()
            # Expired.
            if expiry_date < today:
                color = "red"
            # Expires within 30 days.
            elif expiry_date < today + timedelta(days=30):
                color = "orange"
            # Expires more than 30 days from today.
            else:
                color = "green"
            expiry_date = format_html(
                '<span style="color: {}">{}</span>',
                color,
                localize(expiry_date),
            )
        return expiry_date

